const StorePayment = require('../models/StorePayment');
const { paymentFactory } = require('../payments');
const IdempotencyManager = require('../utils/idempotency');
const RateLimiter = require('../utils/rateLimit');

// 创建速率限制器
const purchaseLimiter = new RateLimiter(10000, 5); // 10秒内最多5次购买
const rechargeLimiter = new RateLimiter(10000, 3); // 10秒内最多3次充值

class StorePaymentController {
  /**
   * 获取商店商品列表
   */
  static async getStoreItems(req, res) {
    try {
      const { db } = require('../config/database');
      const { active = '1' } = req.query;

      const items = await db('store_items')
        .where('active', active === '1')
        .orderBy('price_points', 'asc');

      res.json({
        ok: true,
        data: items
      });
    } catch (error) {
      console.error('获取商店商品失败:', error);
      res.status(500).json({
        ok: false,
        error: '服务器内部错误'
      });
    }
  }

  /**
   * 获取用户钱包信息
   */
  static async getWallet(req, res) {
    try {
      const userId = req.user.id;
      const wallet = await StorePayment.getUserWallet(userId);

      res.json({
        ok: true,
        data: wallet
      });
    } catch (error) {
      console.error('获取钱包信息失败:', error);
      res.status(500).json({
        ok: false,
        error: '服务器内部错误'
      });
    }
  }

  /**
   * 购买商品
   */
  static async buyItem(req, res) {
    try {
      const userId = req.user.id;
      const { itemId, quantity = 1 } = req.body;
      const idempotencyKey = req.headers['x-idempotency-key'];

      if (!itemId) {
        return res.status(400).json({
          ok: false,
          error: '商品ID为必填项'
        });
      }

      if (!idempotencyKey) {
        return res.status(400).json({
          ok: false,
          error: '缺少幂等键'
        });
      }

      // 检查幂等性
      const isNewRequest = await IdempotencyManager.checkAndSet(idempotencyKey, 3600);
      if (!isNewRequest) {
        // 重复请求，返回上次的结果
        return res.status(409).json({
          ok: false,
          error: '重复请求'
        });
      }

      // 检查速率限制
      const isAllowed = await purchaseLimiter.isAllowed(`purchase:${userId}`);
      if (!isAllowed) {
        return res.status(429).json({
          ok: false,
          error: '请求过于频繁，请稍后再试'
        });
      }

      const result = await StorePayment.purchaseItem(userId, itemId, quantity);

      res.json({
        ok: true,
        data: {
          message: '购买成功',
          item: result.item,
          quantity: result.quantity,
          totalPrice: result.totalPrice,
          remainingPoints: result.remainingPoints
        }
      });
    } catch (error) {
      console.error('购买商品失败:', error);
      res.status(400).json({
        ok: false,
        error: error.message || '购买失败'
      });
    }
  }

  /**
   * 创建充值会话
   */
  static async createRechargeSession(req, res) {
    try {
      const userId = req.user.id;
      const { channel, amountRmb, points, idempotencyKey } = req.body;

      if (!channel || !amountRmb || !points || !idempotencyKey) {
        return res.status(400).json({
          ok: false,
          error: '缺少必要参数'
        });
      }

      // 检查幂等性
      const isNewRequest = await IdempotencyManager.checkAndSet(idempotencyKey, 3600);
      if (!isNewRequest) {
        return res.status(409).json({
          ok: false,
          error: '重复请求'
        });
      }

      // 检查速率限制
      const isAllowed = await rechargeLimiter.isAllowed(`recharge:${userId}`);
      if (!isAllowed) {
        return res.status(429).json({
          ok: false,
          error: '请求过于频繁，请稍后再试'
        });
      }

      // 创建充值订单
      const orderId = await StorePayment.createRechargeOrder(
        userId, 
        amountRmb, 
        points, 
        channel, 
        idempotencyKey
      );

      // 创建支付订单
      const paymentProvider = paymentFactory.getProvider(channel);
      const paymentOrder = await paymentProvider.createOrder(
        userId,
        amountRmb,
        points,
        idempotencyKey
      );

      res.json({
        ok: true,
        data: {
          orderId: paymentOrder.orderId,
          payUrl: paymentOrder.payUrl,
          qrData: paymentOrder.qrData,
          channel: paymentOrder.channel
        }
      });
    } catch (error) {
      console.error('创建充值会话失败:', error);
      res.status(400).json({
        ok: false,
        error: error.message || '创建充值会话失败'
      });
    }
  }

  /**
   * 获取订单状态
   */
  static async getOrderStatus(req, res) {
    try {
      const { orderId } = req.params;
      const userId = req.user.id;

      const order = await StorePayment.getRechargeOrder(orderId);

      if (!order) {
        return res.status(404).json({
          ok: false,
          error: '订单不存在'
        });
      }

      // 检查订单是否属于当前用户
      if (order.user_id !== userId) {
        return res.status(403).json({
          ok: false,
          error: '无权访问此订单'
        });
      }

      res.json({
        ok: true,
        data: {
          orderId: order.id,
          status: order.status,
          amountRmb: order.amount_rmb,
          points: order.points,
          channel: order.channel,
          createdAt: order.created_at,
          paidAt: order.paid_at
        }
      });
    } catch (error) {
      console.error('获取订单状态失败:', error);
      res.status(500).json({
        ok: false,
        error: '服务器内部错误'
      });
    }
  }

  /**
   * 获取用户库存
   */
  static async getInventory(req, res) {
    try {
      const userId = req.user.id;
      const inventory = await StorePayment.getUserInventory(userId);

      res.json({
        ok: true,
        data: inventory
      });
    } catch (error) {
      console.error('获取库存失败:', error);
      res.status(500).json({
        ok: false,
        error: '服务器内部错误'
      });
    }
  }

  /**
   * 使用道具
   */
  static async useItem(req, res) {
    try {
      const userId = req.user.id;
      const { itemId, quantity = 1 } = req.body;

      if (!itemId) {
        return res.status(400).json({
          ok: false,
          error: '道具ID为必填项'
        });
      }

      const result = await StorePayment.useItem(userId, itemId, quantity);

      res.json({
        ok: true,
        data: {
          message: '道具使用成功',
          remainingQuantity: result.remainingQuantity
        }
      });
    } catch (error) {
      console.error('使用道具失败:', error);
      res.status(400).json({
        ok: false,
        error: error.message || '使用道具失败'
      });
    }
  }

  /**
   * 微信支付回调
   */
  static async wechatCallback(req, res) {
    try {
      const paymentProvider = paymentFactory.getProvider('wechat');
      const callback = await paymentProvider.verifyCallback(
        JSON.stringify(req.body),
        req.headers
      );

      await this.handlePaymentCallback(callback);

      res.json({ code: 'SUCCESS', message: '成功' });
    } catch (error) {
      console.error('微信支付回调处理失败:', error);
      res.status(400).json({ code: 'FAIL', message: '失败' });
    }
  }

  /**
   * 支付宝回调
   */
  static async alipayCallback(req, res) {
    try {
      const paymentProvider = paymentFactory.getProvider('alipay');
      const callback = await paymentProvider.verifyCallback(
        JSON.stringify(req.body),
        req.headers
      );

      await this.handlePaymentCallback(callback);

      res.send('success');
    } catch (error) {
      console.error('支付宝回调处理失败:', error);
      res.send('fail');
    }
  }

  /**
   * 处理支付回调
   */
  static async handlePaymentCallback(callback) {
    const { orderId, success, channel } = callback;

    if (!success) {
      await StorePayment.updateRechargeOrderStatus(orderId, 'failed');
      return;
    }

    // 获取订单信息
    const order = await StorePayment.getRechargeOrder(orderId);
    if (!order) {
      throw new Error('订单不存在');
    }

    if (order.status === 'paid') {
      // 订单已处理，幂等返回
      return;
    }

    // 更新订单状态并给用户加积分
    await StorePayment.updateRechargeOrderStatus(orderId, 'paid', new Date());
    await StorePayment.addUserPoints(
      order.user_id,
      order.points,
      '充值',
      orderId
    );
  }

  /**
   * 模拟支付成功（开发环境）
   */
  static async simulatePayment(req, res) {
    try {
      const { orderId } = req.params;
      
      if (process.env.NODE_ENV === 'production') {
        return res.status(403).json({
          ok: false,
          error: '生产环境不允许模拟支付'
        });
      }

      const mockProvider = paymentFactory.getProvider('mock');
      const success = await mockProvider.simulatePayment(orderId);

      if (success) {
        await this.handlePaymentCallback({
          orderId,
          success: true,
          channel: 'mock'
        });

        res.json({
          ok: true,
          data: { message: '模拟支付成功' }
        });
      } else {
        res.status(400).json({
          ok: false,
          error: '订单不存在'
        });
      }
    } catch (error) {
      console.error('模拟支付失败:', error);
      res.status(500).json({
        ok: false,
        error: '模拟支付失败'
      });
    }
  }
}

module.exports = StorePaymentController;
